import {
  allocateProportionalVnd,
  computeSuggestedAllocationVariance,
  voucherNetTotalWithVariance,
} from '@linm-soft/common-components';
import type { InvoiceLineDto, OrderLineDto } from '../services/bh/models';

export function emptyOrderLine(): OrderLineDto {
  return { materialCode: '', materialName: '', unitCode: 'Cai', quantity: 1, unitPrice: 0, amount: 0 };
}

export function recalcOrderLine(line: OrderLineDto): OrderLineDto {
  const quantity = Number(line.quantity) || 0;
  const unitPrice = Number(line.unitPrice) || 0;
  return { ...line, amount: Math.round(quantity * unitPrice) };
}

export function normalizeOrderLines(lines: OrderLineDto[]): OrderLineDto[] {
  return lines
    .filter(l => l.materialCode.trim())
    .map(l => {
      const { materialName: _n, ...rest } = l;
      return recalcOrderLine(rest);
    });
}

export function orderLinesTotal(lines: OrderLineDto[]): number {
  return lines.reduce((sum, l) => sum + (Number(l.amount) || 0), 0);
}

export function emptyInvoiceLine(): InvoiceLineDto {
  return {
    materialCode: '',
    materialName: '',
    unitCode: 'Cai',
    quantity: 1,
    unitPrice: 0,
    discountRate: 0,
    discountAmount: 0,
    amount: 0,
    taxRate: 0,
    taxAmount: 0,
  };
}

export const MAX_LINE_DISCOUNT_RATE = 100;

export function lineGrossAmount(line: InvoiceLineDto): number {
  const quantity = Number(line.quantity) || 0;
  const unitPrice = Number(line.unitPrice) || 0;
  return Math.round(quantity * unitPrice);
}

export function clampLineDiscountRate(rate: number): number {
  return Math.min(MAX_LINE_DISCOUNT_RATE, Math.max(0, Number(rate) || 0));
}

export function clampLineDiscountAmount(amount: number, gross: number): number {
  const safeGross = Math.max(0, Math.round(gross));
  return Math.min(safeGross, Math.max(0, Math.round(Number(amount) || 0)));
}

export function lineDiscountAmount(line: InvoiceLineDto): number {
  const gross = lineGrossAmount(line);
  const discountRate = clampLineDiscountRate(line.discountRate ?? 0);
  if (discountRate > 0) {
    return Math.round(gross * discountRate / 100);
  }
  return clampLineDiscountAmount(line.discountAmount ?? 0, gross);
}

export function recalcInvoiceLine(line: InvoiceLineDto): InvoiceLineDto {
  const gross = lineGrossAmount(line);
  const discountRate = clampLineDiscountRate(line.discountRate ?? 0);
  const discount = lineDiscountAmount({ ...line, discountRate });
  const amount = Math.max(0, gross - discount);
  const taxRate = Number(line.taxRate) || 0;
  const taxAmount = Math.round(amount * taxRate / 100);
  return { ...line, discountRate, discountAmount: discount, amount, taxAmount };
}

export function hasLineDiscount(lines: InvoiceLineDto[]): boolean {
  return lines.some(l => (Number(l.discountRate) || 0) > 0 || lineDiscountAmount(l) > 0);
}

export function normalizeInvoiceLines(lines: InvoiceLineDto[]): InvoiceLineDto[] {
  return lines
    .filter(l => l.materialCode.trim())
    .map(l => {
      const { materialName: _n, ...rest } = l;
      return recalcInvoiceLine(rest);
    });
}

/** Phân bổ giảm giá tổng xuống dòng — `allocateProportionalVnd` (common). */
export function applyHeaderDiscountToLines(
  lines: InvoiceLineDto[],
  headerDiscountAmount: number,
  allocationKind: 'quantity' | 'amount',
): InvoiceLineDto[] {
  const amount = Math.round(Number(headerDiscountAmount) || 0);
  if (amount <= 0) return lines.map(recalcInvoiceLine);

  const weights = lines.map(l =>
    allocationKind === 'quantity'
      ? Number(l.quantity) || 0
      : lineGrossAmount(l),
  );
  const { lineAllocations } = allocateProportionalVnd(
    amount,
    weights.map(weight => ({ weight })),
  );

  return lines.map((line, index) =>
    recalcInvoiceLine({
      ...line,
      discountRate: 0,
      discountAmount: lineAllocations[index]?.allocated ?? 0,
    }),
  );
}

export type InvoiceTotalsInput = {
  lines: InvoiceLineDto[];
  headerDiscountAmount?: number;
  useHeaderDiscount?: boolean;
  headerDiscountAllocation?: 'quantity' | 'amount';
  varianceAmount?: number;
};

export function invoiceLinesTotal(input: InvoiceLineDto[] | InvoiceTotalsInput): {
  productTotal: number;
  lineDiscountTotal: number;
  headerDiscountTotal: number;
  subTotal: number;
  taxAmount: number;
  varianceAmount: number;
  suggestedVariance: number;
  total: number;
} {
  const config: InvoiceTotalsInput = Array.isArray(input)
    ? { lines: input }
    : input;

  const lineDiscountActive = hasLineDiscount(config.lines);
  const useHeader =
    Boolean(config.useHeaderDiscount)
    && (config.headerDiscountAmount ?? 0) > 0
    && !lineDiscountActive;

  const normalized = useHeader
    ? applyHeaderDiscountToLines(
      config.lines,
      config.headerDiscountAmount ?? 0,
      config.headerDiscountAllocation ?? 'amount',
    )
    : config.lines.map(recalcInvoiceLine);

  const productTotal = normalized.reduce((s, l) => s + lineGrossAmount(l), 0);
  const lineDiscountTotal = normalized.reduce((s, l) => s + lineDiscountAmount(l), 0);
  const headerDiscountTotal = useHeader ? Math.round(config.headerDiscountAmount ?? 0) : 0;

  const taxableBase = Math.max(0, productTotal - lineDiscountTotal);
  const subTotal = normalized.reduce((s, l) => s + l.amount, 0);
  const lineTaxSum = normalized.reduce((s, l) => s + l.taxAmount, 0);
  const rawTaxAmount = lineTaxSum;
  const taxRatio = taxableBase > 0 ? subTotal / taxableBase : 1;
  const scaledHeaderTax = Math.round(rawTaxAmount * taxRatio);
  const taxAmount = lineTaxSum;

  const suggestedVariance = useHeader
    ? computeSuggestedAllocationVariance({ lineTaxSum, scaledHeaderTax })
    : 0;

  const varianceAmount = Math.round(Number(config.varianceAmount) || 0);
  const total = voucherNetTotalWithVariance({ subTotal, taxAmount, varianceAmount });

  return {
    productTotal,
    lineDiscountTotal,
    headerDiscountTotal,
    subTotal,
    taxAmount,
    varianceAmount,
    suggestedVariance,
    total,
  };
}
