import React from 'react';
import styles from './VoucherFormStatusGroup.module.css';

export interface VoucherFormStatusGroupProps {
  /** Nhãn mức xử lý từ init-data (`formatProcessingLevelFromOptions`). */
  processingLevelLabel?: string;
  compact?: boolean;
}

/**
 * Toolbar — chỉ pill **Mức xử lý** (registry). Cấm badge trạng thái BE (`Draft`/`Posted`).
 * `voucher-list-erp.md` §2.1 · `voucher-form-toolbar.md`.
 */
export const VoucherFormStatusGroup: React.FC<VoucherFormStatusGroupProps> = ({
  processingLevelLabel,
  compact = false,
}) => {
  const levelLabel = processingLevelLabel?.trim();
  if (!levelLabel || levelLabel === '—') return null;

  return (
    <span
      className={`${styles.levelPill} ${compact ? styles.levelPillCompact : ''}`}
      data-testid="voucher-processing-level-indicator"
    >
      {levelLabel}
    </span>
  );
};
