import React from 'react';
import { Input, Select, type SelectOption } from '@linm-soft/common-components';
import df from '../../styles/documentForm.module.css';

export type CurrencyPairFieldProps = {
  currencyCode: string;
  exchangeRate: string | number;
  currencyOptions: SelectOption[];
  staticFieldProps?: React.ComponentProps<typeof Input>;
  selectDisabled?: boolean;
  currencyLabel?: string;
  exchangeRateLabel?: string;
  testIdPrefix: string;
  className?: string;
};

/** NT + TG — cặp 6:4 trong một ô grid (`currency-field.md`). */
export const CurrencyPairField: React.FC<CurrencyPairFieldProps> = ({
  currencyCode,
  exchangeRate,
  currencyOptions,
  staticFieldProps = { readOnly: true, disabled: true },
  selectDisabled = false,
  currencyLabel = 'Ngoại tệ',
  exchangeRateLabel = 'Tỷ giá',
  testIdPrefix,
  className,
}) => (
  <div className={className} data-testid={`${testIdPrefix}-field-currencyPair`}>
    <div className={df.currencyPair}>
      <div className={df.currencyPairMain} data-testid={`${testIdPrefix}-field-currencyCode`}>
        <label className={df.label}>{currencyLabel}</label>
        <Select
          data-testid={`${testIdPrefix}-field-currencyCode-select`}
          options={currencyOptions}
          value={currencyCode}
          onChange={() => {}}
          disabled={selectDisabled || currencyOptions.length === 0}
        />
      </div>
      <div className={df.currencyPairRate} data-testid={`${testIdPrefix}-field-exchangeRate`}>
        <label className={df.label}>{exchangeRateLabel}</label>
        <Input type="number" value={exchangeRate} {...staticFieldProps} />
      </div>
    </div>
  </div>
);
